// ============== CSV IMPORT UTILITIES ==============
// Robust CSV parser: handles quoted fields, embedded commas/newlines, escaped quotes, BOM, CRLF.
function parseCSV(text) {
  const rows = []; let row = []; let field = ''; let inQuotes = false;
  text = String(text || '').replace(/^\ufeff/, '');
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (inQuotes) {
      if (c === '"') { if (text[i + 1] === '"') { field += '"'; i++; } else { inQuotes = false; } }
      else { field += c; }
    } else {
      if (c === '"') { inQuotes = true; }
      else if (c === ',') { row.push(field); field = ''; }
      else if (c === '\n') { row.push(field); rows.push(row); row = []; field = ''; }
      else if (c === '\r') { /* skip */ }
      else { field += c; }
    }
  }
  if (field.length > 0 || row.length > 0) { row.push(field); rows.push(row); }
  // Drop fully-empty rows
  return rows.filter(r => r.some(c => String(c).trim() !== ''));
}

// Normalise a header cell for fuzzy matching (lowercase, strip spaces/punctuation).
const _normHdr = (h) => String(h || '').trim().toLowerCase().replace(/[\s._\-/]+/g, '');

// Build a {fieldName: columnIndex} map from a header row using alias dictionaries.
function buildColMap(headerRow, aliasDict) {
  const map = {};
  headerRow.forEach((cell, idx) => {
    const n = _normHdr(cell);
    for (const [field, aliases] of Object.entries(aliasDict)) {
      if (aliases.some(a => _normHdr(a) === n)) { if (map[field] === undefined) map[field] = idx; }
    }
  });
  return map;
}

// Parse a number that may contain Rp, dots, commas, spaces. Returns Number or 0.
function _num(v) {
  if (v == null || v === '') return 0;
  let s = String(v).replace(/[^0-9.,\-]/g, '').trim();
  if (s === '' || s === '-') return 0;
  // If both . and , present, assume . thousand & , decimal (ID) → keep digits only as integer currency
  if (s.includes('.') && s.includes(',')) s = s.replace(/\./g, '').replace(',', '.');
  else if ((s.match(/,/g) || []).length === 1 && (s.match(/\./g) || []).length === 0) s = s.replace(',', '.');
  else s = s.replace(/,/g, '');
  const n = parseFloat(s);
  return isNaN(n) ? 0 : n;
}

// Normalise a date string to YYYY-MM-DD when possible; otherwise return as-is.
function _normDate(v) {
  const s = String(v || '').trim();
  if (!s) return '';
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);
  const m = s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})$/); // dd/mm/yyyy or dd-mm-yyyy
  if (m) {
    let [, d, mo, y] = m; if (y.length === 2) y = '20' + y;
    return `${y}-${String(mo).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
  }
  return s;
}

// Header aliases (ID + EN) → SPH field names.
const SPH_IMPORT_ALIASES = {
  sphNo: ['SPH No', 'No SPH', 'SPH', 'Nomor SPH', 'No Quotation', 'Quotation No'],
  customer: ['Customer', 'Pelanggan', 'Nama Pelanggan', 'Klien', 'Client'],
  customerType: ['Type', 'Tipe', 'Tipe Pelanggan', 'Customer Type', 'Jenis Pelanggan'],
  projectType: ['Project Type', 'Jenis Proyek', 'Tipe Proyek'],
  modality: ['Modality', 'Modalitas', 'Alat', 'Produk'],
  subModality: ['Sub-Modality', 'Sub Modality', 'SubModality', 'Sub Modalitas', 'Tipe Alat'],
  qty: ['Qty', 'Quantity', 'Jumlah', 'Unit'],
  unitPrice: ['Unit Price', 'Harga Satuan', 'Harga'],
  totalValue: ['Total Value', 'Total Nilai', 'Nilai Total', 'Total', 'Nilai'],
  stage: ['Stage', 'Tahap', 'Tahapan'],
  status: ['Status'],
  salesOwner: ['Sales', 'Sales Owner', 'Pemilik Sales', 'Penjual', 'PIC Sales'],
  issuedDate: ['Issue Date', 'Tanggal Terbit', 'Tanggal', 'Date', 'Tgl Terbit'],
  region: ['Region', 'Wilayah', 'Area', 'Daerah'],
  notes: ['Notes', 'Catatan', 'Keterangan', 'Note'],
};

const _STATUS_ALIASES = { won: 'won', menang: 'won', lost: 'lost', kalah: 'lost', active: 'active', aktif: 'active', pending: 'active' };
const _STAGE_VALID = ['sph_issued', 'follow_up', 'negotiation', 'tender', 'po_issued', 'lost'];

// Parse SPH CSV text → array of partial SPH records (validated). Returns {records, errors, total}.
function parseSPHImport(text) {
  const rows = parseCSV(text);
  if (rows.length < 2) return { records: [], errors: ['File kosong atau tidak ada baris data.'], total: 0 };
  const cols = buildColMap(rows[0], SPH_IMPORT_ALIASES);
  if (cols.sphNo === undefined || cols.customer === undefined)
    return { records: [], errors: ['Kolom wajib tidak ditemukan: butuh minimal "SPH No" dan "Customer/Pelanggan".'], total: rows.length - 1 };
  const records = []; const errors = [];
  for (let r = 1; r < rows.length; r++) {
    const row = rows[r]; const get = (f) => cols[f] !== undefined ? String(row[cols[f]] ?? '').trim() : '';
    const sphNo = get('sphNo'); const customer = get('customer');
    if (!sphNo || !customer) { errors.push(`Baris ${r + 1}: dilewati (No SPH / Pelanggan kosong).`); continue; }
    const qty = _num(get('qty')) || 1;
    const unitPrice = _num(get('unitPrice'));
    let totalValue = _num(get('totalValue'));
    if (!totalValue) totalValue = qty * unitPrice;
    const statusRaw = _normHdr(get('status'));
    const status = _STATUS_ALIASES[statusRaw] || 'active';
    let stage = _normHdr(get('stage')).replace(/\s+/g, '_');
    if (!_STAGE_VALID.includes(stage)) stage = status === 'won' ? 'po_issued' : status === 'lost' ? 'lost' : 'sph_issued';
    const rec = {
      sphNo, customer,
      customerType: get('customerType') || 'hospital',
      projectType: get('projectType') || 'private',
      modality: get('modality') || '-',
      subModality: get('subModality') || '-',
      qty, unitPrice, totalValue,
      stage, status,
      salesOwner: get('salesOwner') || '',
      region: get('region') || '-',
      issuedDate: _normDate(get('issuedDate')) || new Date().toISOString().split('T')[0],
      notes: get('notes') || '',
    };
    records.push(rec);
  }
  return { records, errors, total: rows.length - 1 };
}

// Header aliases for Finance payment import.
const PAY_IMPORT_ALIASES = {
  sphNo: ['SPH No', 'No SPH', 'SPH', 'Nomor SPH'],
  type: ['Type', 'Jenis', 'Jenis Pembayaran', 'Payment Type', 'Tipe'],
  amount: ['Amount', 'Jumlah', 'Nominal', 'Nilai', 'Pembayaran'],
  date: ['Date', 'Tanggal', 'Tgl', 'Tanggal Bayar'],
  note: ['Note', 'Catatan', 'Keterangan', 'Notes'],
};
const _PAYTYPE_ALIASES = { dp: 'dp', deposit: 'dp', uangmuka: 'dp', installment: 'installment', cicilan: 'installment', angsuran: 'installment', final: 'final', pelunasan: 'final', lunas: 'final' };

// Parse Finance payment CSV → array of {sphNo, type, amount, date, note}.
function parsePaymentImport(text) {
  const rows = parseCSV(text);
  if (rows.length < 2) return { records: [], errors: ['File kosong atau tidak ada baris data.'], total: 0 };
  const cols = buildColMap(rows[0], PAY_IMPORT_ALIASES);
  if (cols.sphNo === undefined || cols.amount === undefined)
    return { records: [], errors: ['Kolom wajib tidak ditemukan: butuh minimal "SPH No" dan "Amount/Jumlah".'], total: rows.length - 1 };
  const records = []; const errors = [];
  for (let r = 1; r < rows.length; r++) {
    const row = rows[r]; const get = (f) => cols[f] !== undefined ? String(row[cols[f]] ?? '').trim() : '';
    const sphNo = get('sphNo'); const amount = _num(get('amount'));
    if (!sphNo || !amount) { errors.push(`Baris ${r + 1}: dilewati (No SPH / Jumlah kosong).`); continue; }
    const typeRaw = _normHdr(get('type'));
    records.push({ sphNo, type: _PAYTYPE_ALIASES[typeRaw] || 'installment', amount, date: _normDate(get('date')) || new Date().toISOString().split('T')[0], note: get('note') || '' });
  }
  return { records, errors, total: rows.length - 1 };
}

function FinanceModule({ data, setData, t, lang, canEdit, fmt, onWorkflowUpdate, session = {} }) {
  const [tab, setTab] = useState('finance');
  const [expandedPo, setExpandedPo] = useState(null);
  const [paymentForm, setPaymentForm] = useState({ open: false, sphId: null, amount: '', type: 'installment', date: '', note: '' });
  const [confirmDeletePayment, setConfirmDeletePayment] = useState(null);
  const [editingNote, setEditingNote] = useState({ sphId: null, note: '' });
  const [schemeFilter, setSchemeFilter] = useState('all');
  const [financeSearch, setFinanceSearch] = useState('');
  const [financeSort, setFinanceSort] = useState('newest');
  const [financeProductFilter, setFinanceProductFilter] = useState('all');
  const payImportRef = useRef(null);
  const [payImportMsg, setPayImportMsg] = useState(null);

  const handleImportPayments = (e) => {
    const file = e.target.files && e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const { records, errors } = parsePaymentImport(String(ev.target.result || ''));
        if (!records.length) { setPayImportMsg({ ok: false, text: errors[0] || (lang === 'id' ? 'Tidak ada data valid.' : 'No valid data.') }); return; }
        const today = new Date().toISOString().split('T')[0];
        const byNo = new Map(data.map(s => [String(s.sphNo).trim().toLowerCase(), s.id]));
        const addById = new Map(); let applied = 0, unmatched = 0;
        records.forEach(rec => {
          const id = byNo.get(String(rec.sphNo).trim().toLowerCase());
          if (!id) { unmatched++; return; }
          const entry = { id: 'pay_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2, 6), type: rec.type, amount: rec.amount, date: rec.date || today, note: rec.note || '' };
          if (!addById.has(id)) addById.set(id, []);
          addById.get(id).push(entry); applied++;
        });
        setData(prev => prev.map(s => addById.has(s.id) ? { ...s, paymentHistory: [...(Array.isArray(s.paymentHistory) ? s.paymentHistory : []), ...addById.get(s.id)] } : s));
        setPayImportMsg({ ok: true, text: lang === 'id'
          ? `${records.length} baris diproses → ${applied} pembayaran ditambah${unmatched ? `, ${unmatched} tidak cocok (No SPH tak ditemukan)` : ''}.`
          : `${records.length} rows processed → ${applied} payments added${unmatched ? `, ${unmatched} unmatched (SPH No not found)` : ''}.` });
      } catch (err) { setPayImportMsg({ ok: false, text: (lang === 'id' ? 'Gagal membaca file: ' : 'Failed to read file: ') + err.message }); }
    };
    reader.readAsText(file);
    e.target.value = '';
  };
  const downloadPayTemplate = () => {
    const header = ['SPH No', 'Jenis', 'Jumlah', 'Tanggal', 'Catatan'];
    const ex1 = ['SPH/2026/P21', 'dp', '2460000000', '2026-04-01', 'DP 30%'];
    const ex2 = ['SPH/2026/P21', 'pelunasan', '5740000000', '2026-05-20', 'Pelunasan setelah BAST'];
    downloadCSV('HNTI_Template_Import_Pembayaran.csv', [header, ex1, ex2]);
  };

  const poProjects = useMemo(() => data.filter(s => s.poStatus === 'issued'), [data]);
  const financeProductOptions = useMemo(() => [...new Set(poProjects.flatMap(p => [p.modality, p.subModality, p.productBrand, p.brand]).filter(Boolean))].sort(), [poProjects]);
  const filteredPoProjects = useMemo(() => {
    const q = financeSearch.trim().toLowerCase();
    const rows = poProjects.filter(p => {
      const matchScheme = schemeFilter === 'all' || effectiveScheme(p) === schemeFilter;
      const matchProduct = financeProductFilter === 'all' || [p.modality, p.subModality, p.productBrand, p.brand].filter(Boolean).includes(financeProductFilter);
      const matchSearch = !q || [p.sphNo, p.customer, p.subModality, p.modality, p.salesOwner].some(v => String(v || '').toLowerCase().includes(q));
      return matchScheme && matchProduct && matchSearch;
    });
    return rows.slice().sort((a, b) => {
      if (financeSort === 'highest') return (Number(b.totalValue) || 0) - (Number(a.totalValue) || 0);
      if (financeSort === 'lowest') return (Number(a.totalValue) || 0) - (Number(b.totalValue) || 0);
      return new Date(b.issuedDate || b.poIssuedAt || b.lastUpdate || 0) - new Date(a.issuedDate || a.poIssuedAt || a.lastUpdate || 0);
    });
  }, [poProjects, schemeFilter, financeSearch, financeProductFilter, financeSort]);

  const stats = useMemo(() => {
    let totalPOValue = 0, dpReceived = 0, totalReceivedAll = 0, totalOutstanding = 0;
    poProjects.forEach(p => {
      totalPOValue += Number(p.totalValue) || 0;
      const sum = getPaymentSummary(p);
      totalReceivedAll += sum.totalPaid;
      totalOutstanding += sum.outstanding;
      // DP portion: from history, OR from legacy dpPaid flag (data lama tanpa paymentHistory)
      const history = Array.isArray(p.paymentHistory) ? p.paymentHistory : [];
      const dpFromHistory = history.filter(h => h.type === 'dp' || h.type === 'deposit').reduce((s, h) => s + (Number(h.amount) || 0), 0);
      // Bridge for legacy data: if no history but dpPaid=true, assume DP 30% was paid (or scheme dpPercent)
      const sch = effectiveScheme(p);
      const legacyDpPercent = (typeof p.dpPercent === 'number' ? p.dpPercent : (sch === 'dp_installment' ? 30 : sch === 'kso' ? 10 : 0));
      const dpFromLegacy = (history.length === 0 && p.dpPaid) ? (Number(p.totalValue) || 0) * (legacyDpPercent / 100) : 0;
      dpReceived += dpFromHistory + dpFromLegacy;
    });
    return {
      totalPOValue, dpReceived, totalReceivedAll, totalOutstanding,
      countDPInst: poProjects.filter(p => effectiveScheme(p) === 'dp_installment').length,
      countAfterBast: poProjects.filter(p => effectiveScheme(p) === 'after_bast').length,
      countKSO: poProjects.filter(p => effectiveScheme(p) === 'kso').length,
    };
  }, [poProjects]);
  const { totalPOValue, dpReceived, totalReceivedAll, totalOutstanding, countDPInst, countAfterBast, countKSO } = stats;

  // CRUD payment
  const recordPayment = () => {
    if (!canEdit || !paymentForm.amount) return;
    const amt = parseFloat(paymentForm.amount);
    if (!amt || amt <= 0) return;
    const sphId = paymentForm.sphId;
    const resetFields = { open: true, sphId, amount: '', type: 'installment', date: new Date().toISOString().split('T')[0], note: '', editId: null };
    // EDIT mode: update existing payment entry (fix wrong amount/date/type)
    if (paymentForm.editId) {
      setData(prev => prev.map(s => s.id === sphId ? {
        ...s,
        paymentHistory: (s.paymentHistory || []).map(h => h.id === paymentForm.editId
          ? { ...h, date: paymentForm.date || h.date, amount: amt, type: paymentForm.type, note: paymentForm.note || '', editedAt: new Date().toISOString() }
          : h)
      } : s));
      setPaymentForm(resetFields); // stay open so the updated list is visible
      return;
    }
    const payment = {
      id: 'pay_' + Date.now(),
      date: paymentForm.date || new Date().toISOString().split('T')[0],
      amount: amt,
      type: paymentForm.type,
      note: paymentForm.note || '',
      recordedAt: new Date().toISOString(),
    };
    setData(prev => prev.map(s => s.id === sphId ? { ...s, paymentHistory: [...(s.paymentHistory || []), payment] } : s));
    setPaymentForm(resetFields); // stay open so the new payment appears in the list
  };
  // Open modal in EDIT mode pre-filled with an existing payment
  const openEditPayment = (sphId, h) => {
    setPaymentForm({ open: true, sphId, editId: h.id, amount: String(h.amount), type: h.type, date: h.date, note: h.note || '' });
  };
  const deletePayment = () => {
    if (!confirmDeletePayment) return;
    const { sphId, paymentId } = confirmDeletePayment;
    setData(prev => prev.map(s => s.id === sphId ? { ...s, paymentHistory: (s.paymentHistory || []).filter(h => h.id !== paymentId) } : s));
    setConfirmDeletePayment(null);
  };
  const savePaymentNote = () => {
    setData(prev => prev.map(s => s.id === editingNote.sphId ? { ...s, paymentNote: editingNote.note } : s));
    setEditingNote({ sphId: null, note: '' });
  };
  const markFinanceDocsReady = (p) => {
    if (!onWorkflowUpdate) return;
    onWorkflowUpdate(p.id, {
      financeDocsStatus: 'ready_for_sales',
      financeDocsReadyAt: new Date().toISOString(),
      sphWorkflowStatus: 'invoice_ready',
      workflowEvent: 'invoice_ready',
    }, {
      note: 'Invoice + kwitansi + konfirmasi pesanan ready',
      notify: { target: { username: p.salesOwner }, payload: { type: 'invoice_ready', message: `Invoice+kwitansi dan konfirmasi pesanan ${p.customer} sudah siap diunduh.`, link: { view: 'finance', id: p.id } } },
    });
  };
  const confirmDpReceived = (p) => {
    const dpAmt = (Number(p.totalValue) || 0) * ((Number(p.dpPercent) || 30) / 100);
    const payment = { id: 'pay_dp_confirm_' + Date.now(), date: new Date().toISOString().split('T')[0], amount: dpAmt, type: p.projectType === 'kso' ? 'deposit' : 'dp', note: 'DP/deposit dikonfirmasi Finance', recordedAt: new Date().toISOString() };
    setData(prev => prev.map(s => s.id === p.id ? { ...s, dpPaid: true, dpDecisionAt: new Date().toISOString(), dpConfirmedAt: new Date().toISOString(), sphWorkflowStatus: 'dp_confirmed', nextAction: 'Finance membuat PO ke manufacture', paymentHistory: [...(s.paymentHistory || []), payment] } : s));
    if (onWorkflowUpdate) {
      onWorkflowUpdate(p.id, { sphWorkflowStatus: 'dp_confirmed', dpDecisionAt: new Date().toISOString(), dpConfirmedAt: new Date().toISOString(), principalPoStatus: 'ready_to_issue', workflowEvent: 'dp_confirmed', nextAction: 'Finance membuat PO ke manufacture' }, {
        note: 'DP confirmed by Finance',
        notify: { target: { role: 'finance' }, payload: { type: 'dp_paid', message: `DP/deposit ${p.customer} sudah diterima. Finance dapat membuat PO ke manufacture.`, link: { view: 'finance', id: p.id } } },
      });
    }
  };
  const markPrincipalPoSent = (p) => {
    if (!onWorkflowUpdate) return;
    onWorkflowUpdate(p.id, {
      manufacturePoCreatedAt: new Date().toISOString(),
      principalPoStatus: 'sent',
      principalPoSentAt: new Date().toISOString(),
      sphWorkflowStatus: 'principal_po_sent',
      workflowEvent: 'principal_po_sent',
      nextAction: 'Manager Operasional mengatur import/clearance',
    }, { note: 'PO principal sent' });
  };
  const canDownloadPrincipalPo = ['super_admin', 'gm', 'operations'].includes(session.role);
  const canDownloadInvoiceFor = (p) => ['super_admin', 'gm', 'finance'].includes(session.role) || (session.role === 'sales' && (session.salesId === p.salesOwner || session.username === p.salesOwner));
  const markFinanceDocEdited = (p) => {
    if (!onWorkflowUpdate) return;
    onWorkflowUpdate(p.id, { financeDocsStatus: 'drafting', financeDocsEditedAt: new Date().toISOString(), workflowEvent: 'finance_docs_edited' }, { note: 'Finance document draft edited' });
  };

  // CSV export for AR ledger
  const exportCSV = () => {
    const header = [
      lang === 'id' ? 'No SPH' : 'SPH No', lang === 'id' ? 'Pelanggan' : 'Customer',
      lang === 'id' ? 'Tipe' : 'Type', lang === 'id' ? 'Skema Bayar' : 'Payment Scheme',
      lang === 'id' ? 'Nilai PO' : 'PO Value',
      'DP%', lang === 'id' ? 'Cicilan (bulan)' : 'Installments (months)',
      lang === 'id' ? 'Total Diterima' : 'Total Received',
      lang === 'id' ? 'Tertunggak' : 'Outstanding',
      '% Lunas / Paid %',
      lang === 'id' ? 'Tanggal PO' : 'PO Date',
      lang === 'id' ? 'Keterangan' : 'Notes',
    ];
    const rows = [header];
    filteredPoProjects.forEach(p => {
      const sum = getPaymentSummary(p);
      rows.push([
        p.sphNo, p.customer, p.customerType, effectiveScheme(p),
        p.totalValue, p.dpPercent || 0, p.installmentMonths || 0,
        sum.totalPaid, sum.outstanding, sum.pctPaid,
        p.issuedDate, p.paymentNote || '',
      ]);
    });
    const ts = new Date().toISOString().split('T')[0];
    downloadCSV(`HNTI_AR_Ledger_${ts}.csv`, rows);
  };
  const exportPaymentHistoryCSV = () => {
    const header = [
      lang === 'id' ? 'No SPH' : 'SPH No', lang === 'id' ? 'Pelanggan' : 'Customer',
      lang === 'id' ? 'Tanggal Bayar' : 'Payment Date',
      lang === 'id' ? 'Jenis' : 'Type', lang === 'id' ? 'Jumlah' : 'Amount',
      lang === 'id' ? 'Keterangan' : 'Note',
    ];
    const rows = [header];
    filteredPoProjects.forEach(p => {
      (p.paymentHistory || []).forEach(h => {
        rows.push([p.sphNo, p.customer, h.date, h.type, h.amount, h.note || '']);
      });
    });
    const ts = new Date().toISOString().split('T')[0];
    downloadCSV(`HNTI_Payment_History_${ts}.csv`, rows);
  };

  const schemeColor = (s) => s === 'kso' ? '#7b3fb5' : s === 'after_bast' ? '#1a4d8a' : 'var(--ims-gold)';
  const schemeLabel = (s) => {
    if (s === 'kso') return lang === 'id' ? 'KSO (Deposit + Bagi Hasil)' : 'KSO (Deposit + Revenue Share)';
    if (s === 'after_bast') return lang === 'id' ? 'Project Pemerintah (100% setelah BAST)' : 'Government Project (100% after BAST)';
    return lang === 'id' ? 'DP + Cicilan (Swasta)' : 'DP + Installment (Private)';
  };
  const paymentTypeLabel = (type) => {
    const map = {
      dp: lang === 'id' ? 'DP' : 'DP',
      deposit: lang === 'id' ? 'Deposit' : 'Deposit',
      installment: lang === 'id' ? 'Cicilan' : 'Installment',
      revenue_share: lang === 'id' ? 'Bagi Hasil' : 'Revenue Share',
      full_after_bast: lang === 'id' ? 'Pelunasan Project Pemerintah (Setelah BAST)' : 'Government Project Payment (After BAST)',
      other: lang === 'id' ? 'Lainnya' : 'Other',
    };
    return map[type] || type;
  };

  return (
    <div>
      <div style={{marginBottom: '22px'}}>
        <div style={{fontSize: '11px', letterSpacing: '0.3em', color: 'var(--ims-text-2)', textTransform: 'uppercase', marginBottom: '6px'}}>{t.nav_finance}</div>
        <h1 className="serif hero-title" style={{fontSize: '36px', fontWeight: 500, letterSpacing: '-0.02em', margin: 0, lineHeight: 1.1}}>
          {tab === 'finance' ? t.finance_title : t.np_title}
        </h1>
        <div style={{fontSize: '13px', color: 'var(--ims-text-2)', marginTop: '6px'}}>
          {tab === 'finance' ? t.finance_subtitle : t.np_subtitle}
        </div>
      </div>
      {!canEdit && <ReadOnlyBanner t={t} />}

      {/* Tabs */}
      <div style={{display: 'flex', gap: '2px', marginBottom: '22px', borderBottom: '1px solid var(--ims-border)', flexWrap: 'wrap'}}>
        {[
          { id: 'finance', label: t.np_tab_finance, icon: Wallet },
          { id: 'profit', label: t.np_tab_profit, icon: TrendingUp },
        ].map(tb => {
          const Icon = tb.icon;
          const active = tab === tb.id;
          return (
            <button key={tb.id} onClick={() => setTab(tb.id)} style={{background: 'transparent', border: 'none', padding: '10px 18px', cursor: 'pointer', fontFamily: 'inherit', fontSize: '12px', fontWeight: 500, color: active ? 'var(--ims-accent)' : 'var(--ims-text-2)', borderBottom: active ? '2px solid var(--ims-border)' : '2px solid transparent', marginBottom: '-1px', display: 'flex', alignItems: 'center', gap: '7px', letterSpacing: '0.03em'}}>
              <Icon size={14} strokeWidth={1.5} />{tb.label}
            </button>
          );
        })}
      </div>

      {tab === 'profit' && <NetProfitAnalysis data={data} t={t} lang={lang} fmt={fmt} />}

      {tab === 'finance' && (
      <>
      <div className="kpi-grid-4" style={{display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '1px', background: 'var(--ims-border)', marginBottom: '24px', border: '1px solid var(--ims-border)'}}>
        <KPICard label={t.po_value} value={fmt(totalPOValue)} sublabel={`${poProjects.length} PO`} trend={18.5} />
        <KPICard label={t.cash_collected} value={fmt(totalReceivedAll)} sublabel={lang === 'id' ? 'Total diterima' : 'Total received'} trend={22.1} />
        <KPICard label={t.ar_outstanding} value={fmt(totalOutstanding)} sublabel={lang === 'id' ? 'Belum diterima' : 'Not yet received'} trend={-5.3} />
        <KPICard label={t.dp_paid} value={fmt(dpReceived)} sublabel="DP / Deposit" trend={12.0} />
      </div>

      <div style={{display: 'flex', gap: '8px', alignItems: 'center', flexWrap: 'wrap', marginBottom: '12px'}}>
        <div style={{position: 'relative', flex: '1 1 240px', maxWidth: '360px'}}>
          <Search size={13} style={{position: 'absolute', left: '10px', top: '50%', transform: 'translateY(-50%)', color: 'var(--ims-text-2)'}} />
          <input value={financeSearch} onChange={e => setFinanceSearch(e.target.value)} placeholder={lang === 'id' ? 'Cari SPH, pelanggan, produk, sales...' : 'Search SPH, customer, product, sales...'} style={{paddingLeft: '32px', fontSize: '12px'}} />
        </div>
        <select value={financeSort} onChange={e => setFinanceSort(e.target.value)} style={{width: 'auto', minWidth: '150px'}}>
          <option value="newest">{lang === 'id' ? 'SPH Terbaru' : 'Newest SPH'}</option>
          <option value="highest">{lang === 'id' ? 'Nilai Tertinggi' : 'Highest Value'}</option>
          <option value="lowest">{lang === 'id' ? 'Nilai Terendah' : 'Lowest Value'}</option>
        </select>
        <select value={financeProductFilter} onChange={e => setFinanceProductFilter(e.target.value)} style={{width: 'auto', minWidth: '180px'}}>
          <option value="all">{lang === 'id' ? 'Semua Produk' : 'All Products'}</option>
          {financeProductOptions.map(p => <option key={p} value={p}>{p}</option>)}
        </select>
      </div>

      {/* Scheme summary + export buttons */}
      <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '12px', marginBottom: '14px'}}>
        <div style={{display: 'flex', gap: '8px', flexWrap: 'wrap', alignItems: 'center'}}>
          <span style={{fontSize: '10px', letterSpacing: '0.15em', textTransform: 'uppercase', color: 'var(--ims-text-2)', fontWeight: 600}}>{lang === 'id' ? 'Filter Skema' : 'Scheme Filter'}:</span>
          {[
            { id: 'all', label: lang === 'id' ? `Semua (${poProjects.length})` : `All (${poProjects.length})` },
            { id: 'dp_installment', label: `DP+Cicilan (${countDPInst})` },
            { id: 'after_bast', label: `${lang === 'id' ? 'Project Pemerintah' : 'Government'} (${countAfterBast})` },
            { id: 'kso', label: `KSO (${countKSO})` },
          ].map(opt => (
            <button key={opt.id} onClick={() => setSchemeFilter(opt.id)} style={{background: schemeFilter === opt.id ? 'var(--ims-accent)' : 'transparent', border: `1px solid ${schemeFilter === opt.id ? 'var(--ims-accent)' : 'var(--ims-border)'}`, color: schemeFilter === opt.id ? '#fff' : 'var(--ims-text-2)', padding: '5px 11px', fontSize: '11px', fontFamily: 'inherit', cursor: 'pointer', fontWeight: 500}}>{opt.label}</button>
          ))}
        </div>
        <div style={{display: 'flex', gap: '8px'}}>
          <button onClick={exportCSV} style={{background: 'var(--ims-accent-2)', border: 'none', color: '#fff', padding: '7px 14px', fontSize: '11px', fontFamily: 'inherit', cursor: 'pointer', fontWeight: 600, display: 'flex', alignItems: 'center', gap: '6px'}} title={lang === 'id' ? 'Export ringkasan AR ke CSV (buka di Excel)' : 'Export AR summary to CSV (opens in Excel)'}>
            <FileText size={13} />{lang === 'id' ? 'Export AR (CSV)' : 'Export AR (CSV)'}
          </button>
          <button onClick={exportPaymentHistoryCSV} style={{background: 'transparent', border: '1px solid var(--ims-accent-2)', color: 'var(--ims-accent-2)', padding: '7px 14px', fontSize: '11px', fontFamily: 'inherit', cursor: 'pointer', fontWeight: 600, display: 'flex', alignItems: 'center', gap: '6px'}} title={lang === 'id' ? 'Export riwayat pembayaran ke CSV' : 'Export payment history to CSV'}>
            <FileText size={13} />{lang === 'id' ? 'Export Riwayat Bayar' : 'Export Payment History'}
          </button>
          {canEdit && <>
            <button onClick={() => payImportRef.current && payImportRef.current.click()} style={{background: '#1a4d8a', border: 'none', color: '#fff', padding: '7px 14px', fontSize: '11px', fontFamily: 'inherit', cursor: 'pointer', fontWeight: 600, display: 'flex', alignItems: 'center', gap: '6px'}} title={lang === 'id' ? 'Impor data pembayaran dari CSV' : 'Import payment data from CSV'}>
              <Upload size={13} />{lang === 'id' ? 'Impor Pembayaran' : 'Import Payments'}
            </button>
            <button onClick={downloadPayTemplate} style={{background: 'transparent', border: '1px solid var(--ims-accent)', color: 'var(--ims-text-2)', padding: '7px 14px', fontSize: '11px', fontFamily: 'inherit', cursor: 'pointer', fontWeight: 600, display: 'flex', alignItems: 'center', gap: '6px'}} title={lang === 'id' ? 'Unduh template CSV pembayaran' : 'Download payment CSV template'}>
              <Download size={13} />Template
            </button>
            <input ref={payImportRef} type="file" accept=".csv,text/csv" onChange={handleImportPayments} style={{display: 'none'}} />
          </>}
        </div>
      </div>
      {payImportMsg && <div style={{margin: '0 0 14px', padding: '10px 14px', fontSize: '12px', border: '1px solid', borderColor: payImportMsg.ok ? 'var(--ims-accent-2)' : '#c03030', background: payImportMsg.ok ? 'rgba(58,107,58,0.08)' : 'rgba(192,48,48,0.08)', color: payImportMsg.ok ? '#2c5530' : '#a02020', display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '12px'}}>
        <span>{payImportMsg.ok ? '✓ ' : '⚠ '}{payImportMsg.text}</span>
        <button onClick={() => setPayImportMsg(null)} style={{background: 'none', border: 'none', cursor: 'pointer', color: 'inherit', fontWeight: 700, fontSize: '14px'}}>×</button>
      </div>}

      <div style={{background: 'var(--ims-bg-card)', border: '1px solid var(--ims-border)', overflowX: 'auto'}}>
        <table style={{width: '100%', borderCollapse: 'collapse', fontSize: '12px', minWidth: '1000px'}}>
          <thead>
            <tr style={{background: 'var(--ims-bg-card-2)'}}>
              <Th></Th><Th>{t.sph_number}</Th><Th>{t.customer}</Th>
              <Th>{lang === 'id' ? 'Skema' : 'Scheme'}</Th>
              <Th align="right">{t.value}</Th>
              <Th align="right">{lang === 'id' ? 'Diterima' : 'Received'}</Th>
              <Th align="right">{lang === 'id' ? 'Tertunggak' : 'Outstanding'}</Th>
              <Th align="center">{lang === 'id' ? 'Progress' : 'Progress'}</Th>
              {canEdit && <Th align="center">{lang === 'id' ? 'Aksi' : 'Action'}</Th>}
            </tr>
          </thead>
          <tbody>
            {filteredPoProjects.map(p => {
              const sum = getPaymentSummary(p);
              const isExpanded = expandedPo === p.id;
              const sch = effectiveScheme(p);
              return (
                <React.Fragment key={p.id}>
                  <tr className="hover-row" style={{borderTop: '1px solid var(--ims-border)'}}>
                    <Td>
                      <button onClick={() => setExpandedPo(isExpanded ? null : p.id)} style={{background: 'transparent', border: 'none', cursor: 'pointer', color: 'var(--ims-text-2)', padding: '2px'}}>
                        <ChevronDown size={14} style={{transform: isExpanded ? 'rotate(180deg)' : 'rotate(0deg)', transition: 'transform 0.2s'}} />
                      </button>
                    </Td>
                    <Td><span className="mono" style={{fontSize: '11px'}}>{p.sphNo}</span></Td>
                    <Td>
                      <div style={{fontWeight: 500}}>{p.customer}</div>
                      <div style={{fontSize: '10px', color: 'var(--ims-text-2)'}}>{p.subModality} · {t[`type_${p.customerType}`]}</div>
                    </Td>
                    <Td><span style={{display: 'inline-block', padding: '3px 8px', fontSize: '10px', background: schemeColor(sch) + '25', color: schemeColor(sch), fontWeight: 600, borderRadius: '3px'}}>{schemeLabel(sch)}</span></Td>
                    <Td align="right"><span className="mono" style={{fontWeight: 500}}>{fmt(p.totalValue)}</span></Td>
                    <Td align="right"><span className="mono" style={{color: 'var(--ims-accent-2)', fontWeight: 500}}>{fmt(sum.totalPaid)}</span></Td>
                    <Td align="right"><span className="mono" style={{color: sum.outstanding > 0 ? '#c03030' : 'var(--ims-text-2)', fontWeight: 500}}>{fmt(sum.outstanding)}</span></Td>
                    <Td align="center">
                      <div style={{display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '3px'}}>
                        <div style={{width: '80px', height: '6px', background: 'var(--ims-border)', overflow: 'hidden'}}>
                          <div style={{height: '100%', width: `${sum.pctPaid}%`, background: sum.pctPaid >= 100 ? 'var(--ims-accent-2)' : 'var(--ims-gold)'}} />
                        </div>
                        <div style={{fontSize: '10px', color: 'var(--ims-text-2)'}}>{sum.pctPaid}%{sum.installmentsExpected > 0 && ` · ${sum.installmentsPaid}/${sum.installmentsExpected}`}</div>
                      </div>
                    </Td>
                    {canEdit && (
                      <Td align="center">
                        <button onClick={() => setPaymentForm({ open: true, sphId: p.id, amount: '', type: sch === 'kso' ? 'revenue_share' : sch === 'after_bast' ? 'full_after_bast' : 'installment', date: new Date().toISOString().split('T')[0], note: '', editId: null })} style={{background: 'var(--ims-bg-alt)', border: 'none', color: '#fff', padding: '5px 11px', fontSize: '10px', cursor: 'pointer', fontFamily: 'inherit', fontWeight: 600, display: 'inline-flex', alignItems: 'center', gap: '5px', whiteSpace: 'nowrap'}} title={lang === 'id' ? 'Kelola pembayaran: tambah / edit / hapus' : 'Manage payments: add / edit / delete'}>
                          <Wallet size={11} />{lang === 'id' ? 'Kelola Bayar' : 'Manage Pay'}{(p.paymentHistory || []).length > 0 ? ` (${(p.paymentHistory || []).length})` : ''}
                        </button>
                      </Td>
                    )}
                  </tr>

                  {/* Expanded payment schedule + history */}
                  {isExpanded && (
                    <tr>
                      <Td></Td>
                      <td colSpan={canEdit ? 8 : 7} style={{padding: '14px 18px', background: 'var(--ims-bg)', borderTop: '1px solid var(--ims-border)'}}>
                        <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '12px', flexWrap: 'wrap', padding: '12px', background: 'var(--ims-bg-card)', border: '1px solid var(--ims-border)'}}>
                          <div>
                            <div style={{fontSize: '11px', color: 'var(--ims-text-2)', fontWeight: 700, letterSpacing: '0.12em', textTransform: 'uppercase'}}>{lang === 'id' ? 'Konfirmasi DP / Deposit' : 'DP / Deposit Confirmation'}</div>
                            <div style={{fontSize: '12px', color: 'var(--ims-text-2)', marginTop: '4px'}}>{p.customer} · {p.sphNo} · DP {p.dpPercent || 0}%</div>
                          </div>
                          {canEdit && <button onClick={() => confirmDpReceived(p)} style={{background: 'var(--ims-gold)', color: 'var(--ims-accent-ink)', border: 'none', padding: '8px 12px', fontSize: '11px', cursor: 'pointer', fontWeight: 800}}>{lang === 'id' ? 'Pembayaran DP telah diterima' : 'DP Payment Received'}</button>}
                        </div>
                      </td>
                    </tr>
                  )}
                </React.Fragment>
              );
            })}
          </tbody>
        </table>
        {filteredPoProjects.length === 0 && <div className="empty-state">{t.no_data}</div>}
      </div>

      {/* Manage Payments Modal — list + inline edit/delete + add form (Catatan #3) */}
      {paymentForm.open && (() => {
        const modalSph = data.find(s => s.id === paymentForm.sphId);
        const history = modalSph && Array.isArray(modalSph.paymentHistory) ? modalSph.paymentHistory : [];
        const typeLabel = (ty) => ({ dp: 'DP', deposit: 'Deposit (KSO)', installment: lang === 'id' ? 'Cicilan' : 'Installment', revenue_share: lang === 'id' ? 'Bagi Hasil' : 'Rev. Share', full_after_bast: lang === 'id' ? 'Pelunasan (BAST)' : 'Full (BAST)', other: lang === 'id' ? 'Lainnya' : 'Other' }[ty] || ty);
        return (
        <div className="modal-overlay" onClick={() => setPaymentForm({ ...paymentForm, open: false, editId: null })} style={{zIndex: 9999}}>
          <div onClick={e => e.stopPropagation()} style={{background: 'var(--ims-bg-card)', maxWidth: '620px', width: '94%', maxHeight: '88vh', overflowY: 'auto', border: '1px solid var(--ims-border)', boxShadow: '0 20px 60px rgba(0,0,0,0.3)'}}>
            <div style={{padding: '18px 22px', borderBottom: '1px solid var(--ims-border)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, background: 'var(--ims-bg-card)', zIndex: 2}}>
              <div>
                <h3 className="serif" style={{margin: 0, fontSize: '18px', fontWeight: 500}}>{lang === 'id' ? 'Kelola Pembayaran' : 'Manage Payments'}</h3>
                {modalSph && <div style={{fontSize: '11px', color: 'var(--ims-text-2)', marginTop: '2px'}}>{modalSph.customer} · {modalSph.sphNo}</div>}
              </div>
              <button onClick={() => setPaymentForm({ ...paymentForm, open: false, editId: null })} style={{background: 'transparent', border: 'none', cursor: 'pointer'}}><X size={18} /></button>
            </div>

            {/* Existing payments with inline EDIT + DELETE */}
            <div style={{padding: '16px 22px 4px'}}>
              <div style={{fontSize: '10px', letterSpacing: '0.15em', textTransform: 'uppercase', color: 'var(--ims-text-2)', fontWeight: 600, marginBottom: '8px'}}>{lang === 'id' ? `Riwayat Pembayaran (${history.length})` : `Payment History (${history.length})`}</div>
              {history.length === 0 ? (
                <div style={{padding: '14px', background: 'var(--ims-bg)', border: '1px dashed var(--ims-border)', fontSize: '12px', color: 'var(--ims-text-2)', textAlign: 'center'}}>{lang === 'id' ? 'Belum ada pembayaran. Tambahkan di bawah.' : 'No payments yet. Add one below.'}</div>
              ) : (
                <div style={{border: '1px solid var(--ims-border)'}}>
                  {history.map((h, idx) => (
                    <div key={h.id} style={{display: 'flex', alignItems: 'center', gap: '10px', padding: '9px 12px', borderBottom: idx < history.length - 1 ? '1px solid var(--ims-bg-card-2)' : 'none', background: paymentForm.editId === h.id ? 'rgba(26,77,138,0.07)' : 'transparent'}}>
                      <div style={{flex: 1, minWidth: 0}}>
                        <div style={{fontSize: '12.5px', fontWeight: 600, color: 'var(--ims-text)'}}>{fmt(h.amount)}</div>
                        <div style={{fontSize: '10.5px', color: 'var(--ims-text-2)'}}>{h.date} · {typeLabel(h.type)}{h.note ? ` · ${h.note}` : ''}</div>
                      </div>
                      {canEdit && <>
                        <button onClick={() => setPaymentForm({ open: true, sphId: modalSph.id, editId: h.id, amount: String(h.amount), type: h.type, date: h.date, note: h.note || '' })} style={{flexShrink: 0, background: '#1a4d8a', border: 'none', padding: '4px 10px', fontSize: '10px', cursor: 'pointer', color: '#fff', fontFamily: 'inherit', fontWeight: 600, display: 'flex', alignItems: 'center', gap: '4px'}}><Edit2 size={10} />{lang === 'id' ? 'Edit' : 'Edit'}</button>
                        <button onClick={() => setConfirmDeletePayment({ sphId: modalSph.id, paymentId: h.id })} style={{flexShrink: 0, background: 'transparent', border: '1px solid #c03030', padding: '4px 10px', fontSize: '10px', cursor: 'pointer', color: '#c03030', fontFamily: 'inherit', fontWeight: 600, display: 'flex', alignItems: 'center', gap: '4px'}}><Trash2 size={10} />{lang === 'id' ? 'Hapus' : 'Delete'}</button>
                      </>}
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Add / Edit form */}
            <div style={{padding: '8px 22px 4px'}}>
              <div style={{fontSize: '10px', letterSpacing: '0.15em', textTransform: 'uppercase', color: paymentForm.editId ? '#1a4d8a' : 'var(--ims-accent-2)', fontWeight: 700, marginTop: '10px', marginBottom: '6px'}}>{paymentForm.editId ? (lang === 'id' ? '✎ Edit Pembayaran Terpilih' : '✎ Editing Selected Payment') : (lang === 'id' ? '+ Tambah Pembayaran Baru' : '+ Add New Payment')}</div>
            </div>
            <div style={{padding: '4px 22px 20px', display: 'flex', flexDirection: 'column', gap: '12px'}}>
              <div>
                <label style={{display: 'block', fontSize: '10px', letterSpacing: '0.15em', textTransform: 'uppercase', color: 'var(--ims-text-2)', fontWeight: 600, marginBottom: '4px'}}>{lang === 'id' ? 'Tanggal Pembayaran' : 'Payment Date'}</label>
                <input type="date" value={paymentForm.date} onChange={e => setPaymentForm({ ...paymentForm, date: e.target.value })} style={{width: '100%'}} />
              </div>
              <div>
                <label style={{display: 'block', fontSize: '10px', letterSpacing: '0.15em', textTransform: 'uppercase', color: 'var(--ims-text-2)', fontWeight: 600, marginBottom: '4px'}}>{lang === 'id' ? 'Jenis Pembayaran' : 'Payment Type'}</label>
                <select value={paymentForm.type} onChange={e => setPaymentForm({ ...paymentForm, type: e.target.value })} style={{width: '100%'}}>
                  <option value="dp">DP</option>
                  <option value="deposit">Deposit (KSO)</option>
                  <option value="installment">{lang === 'id' ? 'Cicilan' : 'Installment'}</option>
                  <option value="revenue_share">{lang === 'id' ? 'Bagi Hasil (KSO)' : 'Revenue Share (KSO)'}</option>
                  <option value="full_after_bast">{lang === 'id' ? 'Pelunasan Project Pemerintah (Setelah BAST)' : 'Government Project Payment (After BAST)'}</option>
                  <option value="other">{lang === 'id' ? 'Lainnya' : 'Other'}</option>
                </select>
              </div>
              <div>
                <label style={{display: 'block', fontSize: '10px', letterSpacing: '0.15em', textTransform: 'uppercase', color: 'var(--ims-text-2)', fontWeight: 600, marginBottom: '4px'}}>{lang === 'id' ? 'Jumlah (Rp)' : 'Amount (Rp)'}</label>
                <input type="number" value={paymentForm.amount} onChange={e => setPaymentForm({ ...paymentForm, amount: e.target.value })} placeholder="0" style={{width: '100%'}} />
              </div>
              <div>
                <label style={{display: 'block', fontSize: '10px', letterSpacing: '0.15em', textTransform: 'uppercase', color: 'var(--ims-text-2)', fontWeight: 600, marginBottom: '4px'}}>{lang === 'id' ? 'Keterangan' : 'Note'}</label>
                <textarea value={paymentForm.note} onChange={e => setPaymentForm({ ...paymentForm, note: e.target.value })} rows={2} placeholder={lang === 'id' ? 'Contoh: Transfer BCA 6011***, no. ref XYZ' : 'E.g.: BCA transfer 6011***, ref no XYZ'} style={{width: '100%'}} />
              </div>
            </div>
            <div style={{padding: '14px 22px', borderTop: '1px solid var(--ims-border)', background: 'var(--ims-bg)', display: 'flex', justifyContent: 'space-between', gap: '10px', position: 'sticky', bottom: 0}}>
              {paymentForm.editId
                ? <button onClick={() => setPaymentForm({ ...paymentForm, editId: null, amount: '', type: 'installment', date: new Date().toISOString().split('T')[0], note: '' })} style={{background: 'transparent', border: '1px solid var(--ims-text-2)', padding: '8px 14px', fontSize: '12px', cursor: 'pointer', color: 'var(--ims-text-2)', fontFamily: 'inherit'}}>{lang === 'id' ? '↩ Batal Edit' : '↩ Cancel Edit'}</button>
                : <span />}
              <div style={{display: 'flex', gap: '10px'}}>
                <button onClick={() => setPaymentForm({ ...paymentForm, open: false, editId: null })} style={{background: 'transparent', border: '1px solid var(--ims-border)', padding: '8px 16px', fontSize: '12px', cursor: 'pointer', color: 'var(--ims-text-2)', fontFamily: 'inherit'}}>{lang === 'id' ? 'Tutup' : 'Close'}</button>
                <button onClick={recordPayment} style={{background: paymentForm.editId ? '#1a4d8a' : 'var(--ims-accent)', border: 'none', padding: '8px 16px', fontSize: '12px', cursor: 'pointer', color: '#fff', fontFamily: 'inherit', fontWeight: 600}}>{paymentForm.editId ? (lang === 'id' ? 'Simpan Perubahan' : 'Save Changes') : (lang === 'id' ? 'Tambah Pembayaran' : 'Add Payment')}</button>
              </div>
            </div>
          </div>
        </div>
        );
      })()}

      <ConfirmDialog open={!!confirmDeletePayment} title={lang === 'id' ? 'Hapus Catatan Pembayaran?' : 'Delete Payment Record?'} message={lang === 'id' ? 'Catatan pembayaran ini akan dihapus permanen.' : 'This payment record will be permanently deleted.'} confirmText={lang === 'id' ? 'Ya, Hapus' : 'Yes, Delete'} onConfirm={deletePayment} onCancel={() => setConfirmDeletePayment(null)} danger lang={lang} />
      </>
      )}
    </div>
  );
}

// ============== Net Profit Analysis Sub-Component ==============
function NetProfitAnalysis({ data, t, lang, fmt }) {
  const computed = useMemo(() => {
    // Won + PO Issued deals count as revenue realized
    const realizedDeals = data.filter(s => s.poStatus === 'issued' || s.status === 'won');
    const totalRevenue = realizedDeals.reduce((sum, s) => sum + calcNetProfit(s).revenue, 0);
    const totalProfit = realizedDeals.reduce((sum, s) => sum + calcNetProfit(s).netProfit, 0);
    const avgMargin = totalRevenue > 0 ? (totalProfit / totalRevenue) : 0;
    // Group by modality
    const modalitySet = [...new Set(realizedDeals.map(s => s.modality))];
    const byModality = modalitySet.map(mod => {
      const deals = realizedDeals.filter(s => s.modality === mod);
      const rev = deals.reduce((sum, s) => sum + calcNetProfit(s).revenue, 0);
      const prof = deals.reduce((sum, s) => sum + calcNetProfit(s).netProfit, 0);
      const margin = rev > 0 ? prof / rev : 0;
      return { modality: mod, revenue: rev, profit: prof, margin, count: deals.length, defaultMargin: NET_MARGIN_BY_MODALITY[mod] || NET_MARGIN_DEFAULT };
    }).sort((a, b) => b.profit - a.profit);
    // Monthly trend
    const monthlyTrend = ['Jan', 'Feb', 'Mar', 'Apr', 'Mei'].map((m, i) => {
      const mn = String(i + 1).padStart(2, '0');
      const monthDeals = realizedDeals.filter(s => s.issuedDate?.startsWith(`2026-${mn}`));
      const rev = monthDeals.reduce((sum, s) => sum + calcNetProfit(s).revenue, 0);
      const prof = monthDeals.reduce((sum, s) => sum + calcNetProfit(s).netProfit, 0);
      return { month: m, [t.np_revenue]: rev, [t.np_profit]: prof };
    });
    return { realizedDeals, totalRevenue, totalProfit, avgMargin, byModality, monthlyTrend };
  }, [data, t]);
  const { realizedDeals, totalRevenue, totalProfit, avgMargin, byModality, monthlyTrend } = computed;

  return (
    <div>
      {/* KPI Cards */}
      <div className="kpi-grid-4" style={{display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '1px', background: 'var(--ims-border)', marginBottom: '24px', border: '1px solid var(--ims-border)'}}>
        <div style={{padding: '20px 22px', background: 'var(--ims-bg-card)'}}>
          <div style={{fontSize: '10px', letterSpacing: '0.22em', color: 'var(--ims-text-2)', textTransform: 'uppercase'}}>{t.np_total_revenue}</div>
          <div className="serif" style={{fontSize: '26px', fontWeight: 500, marginTop: '6px'}}>{fmt(totalRevenue)}</div>
          <div style={{fontSize: '10px', color: 'var(--ims-text-2)', marginTop: '6px'}}>{realizedDeals.length} deals · {lang === 'id' ? 'Setelah PPN' : 'After VAT'}</div>
        </div>
        <div style={{padding: '20px 22px', background: 'var(--ims-bg-card)'}}>
          <div style={{fontSize: '10px', letterSpacing: '0.22em', color: 'var(--ims-text-2)', textTransform: 'uppercase'}}>{t.np_total_profit}</div>
          <div className="serif" style={{fontSize: '26px', fontWeight: 500, marginTop: '6px', color: 'var(--ims-accent-2)'}}>{fmt(totalProfit)}</div>
          <div style={{fontSize: '10px', color: 'var(--ims-text-2)', marginTop: '6px'}}>{lang === 'id' ? 'Setelah COGS, Expense, Overhead' : 'After COGS, Expense, Overhead'}</div>
        </div>
        <div style={{padding: '20px 22px', background: 'var(--ims-bg-alt)', color: 'var(--ims-text)'}}>
          <div style={{fontSize: '10px', letterSpacing: '0.22em', color: 'var(--ims-accent)', textTransform: 'uppercase'}}>{t.np_avg_margin}</div>
          <div className="serif" style={{fontSize: '26px', fontWeight: 500, marginTop: '6px', color: '#fff'}}>{(avgMargin * 100).toFixed(1)}%</div>
          <div style={{fontSize: '10px', color: 'rgba(255,255,255,0.6)', marginTop: '6px'}}>Range 11-19% · {lang === 'id' ? 'Industri Distributor' : 'Distributor Industry'}</div>
        </div>
      </div>

      {/* Monthly Trend Chart */}
      <div className="card" style={{marginBottom: '20px'}}>
        <div className="card-title">{t.np_monthly_trend}</div>
        <ResponsiveContainer width="100%" height={260}>
          <BarChart data={monthlyTrend} margin={{top: 5, right: 16, left: 0, bottom: 5}}>
            <CartesianGrid strokeDasharray="3 3" stroke="var(--ims-border)" vertical={false} />
            <XAxis dataKey="month" stroke="var(--ims-text-2)" style={{fontSize: 11}} />
            <YAxis stroke="var(--ims-text-2)" style={{fontSize: 10}} tickFormatter={(v) => v >= 1e9 ? `${(v/1e9).toFixed(0)}M` : v >= 1e6 ? `${(v/1e6).toFixed(0)}Jt` : v} />
            <Tooltip content={<ChartTooltip fmt={fmt} />} />
            <Legend wrapperStyle={{fontSize: '11px'}} />
            <Bar dataKey={t.np_revenue} fill="#1a4d8a" radius={[3, 3, 0, 0]} />
            <Bar dataKey={t.np_profit} fill="var(--ims-accent-2)" radius={[3, 3, 0, 0]} />
          </BarChart>
        </ResponsiveContainer>
      </div>

      {/* Per Modality */}
      <div className="card" style={{marginBottom: '20px'}}>
        <div className="card-title">{t.np_per_modality}</div>
        <div style={{overflowX: 'auto'}}>
          <table style={{width: '100%', borderCollapse: 'collapse', fontSize: '12px', minWidth: '700px'}}>
            <thead>
              <tr style={{background: 'var(--ims-bg-card-2)'}}>
                <Th>{t.np_modality_label}</Th>
                <Th align="right">{t.project_count}</Th>
                <Th align="right">{t.np_revenue}</Th>
                <Th align="right">{t.np_profit}</Th>
                <Th align="right">{t.np_margin}</Th>
                <Th align="right">{t.np_default_margin}</Th>
              </tr>
            </thead>
            <tbody>
              {byModality.map(m => (
                <tr key={m.modality} className="hover-row" style={{borderTop: '1px solid var(--ims-border)'}}>
                  <Td><strong style={{color: MODALITY_COLORS[m.modality] || 'var(--ims-accent)'}}>{m.modality}</strong></Td>
                  <Td align="right">{m.count}</Td>
                  <Td align="right"><span className="mono">{fmt(m.revenue)}</span></Td>
                  <Td align="right"><span className="mono" style={{color: 'var(--ims-accent-2)', fontWeight: 600}}>{fmt(m.profit)}</span></Td>
                  <Td align="right">
                    <span style={{padding: '3px 8px', fontSize: '11px', background: 'var(--ims-accent-2)25', color: 'var(--ims-accent-2)', fontWeight: 700}} className="mono">{(m.margin * 100).toFixed(1)}%</span>
                  </Td>
                  <Td align="right"><span style={{fontSize: '10px', color: 'var(--ims-text-2)'}} className="mono">{(m.defaultMargin * 100).toFixed(0)}%</span></Td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

// Customs status reason editor — local draft + explicit Save button (review #3) so the typed
// reason is committed deliberately, with a clear "saved" confirmation.
function CustomsNoteEditor({ value, isHold, onSave, t, lang }) {
  const [draft, setDraft] = useState(value || '');
  const [justSaved, setJustSaved] = useState(false);
  useEffect(() => { setDraft(value || ''); setJustSaved(false); }, [value]);
  const dirty = draft !== (value || '');
  return (
    <>
      <textarea
        value={draft}
        onChange={e => { setDraft(e.target.value); setJustSaved(false); }}
        placeholder={t.status_note_placeholder}
        rows={2}
        style={{width: '100%', fontSize: '12px', padding: '6px 8px', border: `1px solid ${isHold && !draft.trim() ? '#c03030' : 'var(--ims-border)'}`, background: 'var(--ims-bg-card)', fontFamily: 'inherit', resize: 'vertical'}}
      />
      <div style={{display: 'flex', alignItems: 'center', gap: '10px', marginTop: '6px'}}>
        <button onClick={() => { onSave(draft.trim()); setJustSaved(true); }} disabled={!dirty} style={{padding: '6px 14px', fontSize: '11px', fontFamily: 'inherit', fontWeight: 600, letterSpacing: '0.03em', background: dirty ? 'var(--ims-accent)' : 'var(--ims-border)', color: '#fff', border: 'none', cursor: dirty ? 'pointer' : 'default'}}>{t.status_note_save}</button>
        {justSaved && !dirty && <span style={{fontSize: '11px', color: 'var(--ims-accent-2)', fontWeight: 600}}>✓ {t.status_note_saved}</span>}
      </div>
    </>
  );
}

function OperationsModule({ data, setData, manifests, setManifests, customsDocs, setCustomsDocs, t, lang, canEdit, fmt }) {
  const [tab, setTab] = useState('shipment');
  // Only show PO still in active shipping pipeline (not yet delivered/installed).
  // Historical delivered units are excluded to keep this tab focused on live logistics.
  const poProjects = useMemo(() => data.filter(s =>
    s.poStatus === 'issued' &&
    s.shippingStatus !== 'delivered' &&
    s.installationStatus !== 'installed'
  ), [data]);
  const localProjects = useMemo(() => data.filter(s =>
    s.poStatus === 'issued' &&
    s.installationStatus !== 'installed' &&
    (s.customsStatus === 'released' || s.shippingStatus === 'delivered' || s.localDeliveryStatus)
  ), [data]);
  const totalPoIssued = useMemo(() => data.filter(s => s.poStatus === 'issued').length, [data]);

  // Manifest status → Shipment status mapping (cross-tab link)
  const MANIFEST_TO_SHIPPING = {
    planning: 'plan_order',
    loading: 'ready_to_ship',
    in_transit: 'on_shipment',
    arrived: 'delivered',
    cleared: 'delivered',
  };

  // Build manifest lookup by id for linked SPH
  const manifestById = useMemo(() => new Map(manifests.map(m => [m.id, m])), [manifests]);

  // For a PO project, determine effective shipping status (synced from manifest if linked)
  const getEffectiveShipping = (p) => {
    if (p.manifestId && manifestById.has(p.manifestId)) {
      const mfst = manifestById.get(p.manifestId);
      return MANIFEST_TO_SHIPPING[mfst.status] || p.shippingStatus;
    }
    return p.shippingStatus;
  };

  const updateShipping = (id, status) => {
    if (!canEdit) return;
    const extra = status === 'on_shipment' ? { sphWorkflowStatus: 'import_clearance', importClearanceAt: new Date().toISOString(), nextAction: 'Operasional mengatur import/clearance' }
      : status === 'delivered' ? { sphWorkflowStatus: 'goods_sent_client', goodsSentClientAt: new Date().toISOString(), technicianNotifiedAt: new Date().toISOString(), nextAction: 'Teknisi atur jadwal instalasi' }
      : {};
    setData(prev => prev.map(s => s.id === id ? { ...s, shippingStatus: status, ...extra } : s));
    if (status === 'delivered') {
      notify({ role: 'technician' }, { type: 'install_pending', message: 'Barang sudah dikirim ke klien. Teknisi perlu mengatur jadwal instalasi.', link: { view: 'installation', id } });
    }
  };
  const updateCustoms = (id, status) => {
    if (!canEdit) return;
    // If switching to hold, keep existing note; UI will prompt for note
    const extra = status === 'ongoing' ? { sphWorkflowStatus: 'import_clearance', importClearanceAt: new Date().toISOString() }
      : status === 'released' ? { importClearanceAt: new Date().toISOString(), nextAction: 'Operasional kirim barang ke klien' }
      : {};
    setData(prev => prev.map(s => s.id === id ? { ...s, customsStatus: status, ...extra } : s));
  };
  const updateStatusNote = (id, note) => {
    if (!canEdit) return;
    setData(prev => prev.map(s => s.id === id ? { ...s, customsStatusNote: note } : s));
  };
  const saveStatusNote = (id, note) => {
    if (!canEdit) return;
    setData(prev => prev.map(s => s.id === id ? { ...s, customsStatusNote: note } : s));
    flushPersist();
    showToast(lang === 'id' ? 'Alasan status bea cukai tersimpan' : 'Customs status reason saved', 'success');
  };
  const linkManifest = (id, manifestId) => {
    if (!canEdit) return;
    setData(prev => prev.map(s => s.id === id ? { ...s, manifestId: manifestId || null } : s));
  };
  const updateLocalDelivery = (id, patch) => {
    if (!canEdit) return;
    const extra = patch.localDeliveryStatus || patch.localEta ? { sphWorkflowStatus: 'goods_sent_client', goodsSentClientAt: new Date().toISOString(), technicianNotifiedAt: new Date().toISOString(), nextAction: 'Teknisi atur jadwal instalasi' } : {};
    setData(prev => prev.map(s => s.id === id ? { ...s, ...patch, ...extra } : s));
    if (patch.localEta) {
      const eta = new Date(patch.localEta);
      const days = Math.ceil((eta - new Date()) / 86400000);
      if (!isNaN(days) && days <= 2) {
        notify({ role: 'technician' }, {
          type: 'install_pending',
          message: `Barang proyek akan tiba di RS sekitar ${patch.localEta}. Tim teknisi perlu persiapan instalasi.`,
          link: { view: 'installation', id },
        });
      }
    }
  };

  const shippingSteps = useMemo(() => [
    { id: 'plan_order', label: t.plan_order_to_factory, color: '#94a3b8' },
    { id: 'ready_to_ship', label: t.ready_to_ship, color: '#7d9cc5' },
    { id: 'on_shipment', label: t.on_shipment, color: 'var(--ims-accent)' },
    { id: 'delivered', label: t.delivery_to_site, color: 'var(--ims-accent-2)' },
  ], [t]);

  const opsStats = useMemo(() => ({
    poInShipping: poProjects.length,
    totalManifests: manifests.length,
    inTransit: manifests.filter(m => m.status === 'in_transit').length,
    // "Dokumen Pending" = dokumen yang menunggu tindakan (submitted ke Bea Cukai, menunggu SPPB approval)
    // bukan dokumen yang sudah diterima dari principal (status='received')
    pendingDocs: customsDocs.filter(d => d.status === 'submitted' || d.status === 'pending').length,
  }), [poProjects, manifests, customsDocs]);
  const { poInShipping, totalManifests, inTransit, pendingDocs } = opsStats;

  return (
    <div>
      <div style={{marginBottom: '22px'}}>
        <div style={{fontSize: '11px', letterSpacing: '0.3em', color: 'var(--ims-text-2)', textTransform: 'uppercase', marginBottom: '6px'}}>{t.nav_operations}</div>
        <h1 className="serif hero-title" style={{fontSize: '36px', fontWeight: 500, letterSpacing: '-0.02em', margin: 0, lineHeight: 1.1}}>{t.operations_title}</h1>
        <div style={{fontSize: '13px', color: 'var(--ims-text-2)', marginTop: '6px'}}>{t.operations_subtitle}</div>
      </div>
      {!canEdit && <ReadOnlyBanner t={t} />}

      <div className="kpi-grid-4" style={{display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '1px', background: 'var(--ims-border)', marginBottom: '22px', border: '1px solid var(--ims-border)'}}>
        <div className="card-pad">
          <div className="lbl-tag">{t.ops_po_in_shipping}</div>
          <div className="serif" style={{fontSize: '26px', fontWeight: 500, marginTop: '4px'}}>{poInShipping}</div>
          <div style={{fontSize: '10px', color: 'var(--ims-text-2)', marginTop: '2px'}}>{lang === 'id' ? `dari ${totalPoIssued} PO terbit (sisanya sudah terkirim)` : `of ${totalPoIssued} PO issued (rest delivered)`}</div>
        </div>
        <div className="card-pad">
          <div className="lbl-tag">{t.ops_total_manifests}</div>
          <div className="serif" style={{fontSize: '26px', fontWeight: 500, marginTop: '4px'}}>{totalManifests}</div>
          <div style={{fontSize: '10px', color: 'var(--ims-text-2)', marginTop: '2px'}}>{lang === 'id' ? 'manifest pengapalan aktif' : 'active shipment manifests'}</div>
        </div>
        <div className="card-pad">
          <div className="lbl-tag">{t.ops_in_transit}</div>
          <div className="serif" style={{fontSize: '26px', fontWeight: 500, marginTop: '4px', color: 'var(--ims-accent)'}}>{inTransit}</div>
        </div>
        <div className="card-pad">
          <div className="lbl-tag">{t.ops_pending_docs}</div>
          <div className="serif" style={{fontSize: '26px', fontWeight: 500, marginTop: '4px', color: '#c03030'}}>{pendingDocs}</div>
          <div style={{fontSize: '10px', color: 'var(--ims-text-2)', marginTop: '2px'}}>{lang === 'id' ? 'Disubmit, menunggu SPPB Bea Cukai' : 'Submitted, awaiting customs SPPB'}</div>
        </div>
      </div>

      <div style={{display: 'flex', gap: '2px', marginBottom: '22px', borderBottom: '1px solid var(--ims-border)', flexWrap: 'wrap'}}>
        {[
          { id: 'shipment', label: t.ops_tab_shipment, icon: Truck, count: poProjects.length },
          { id: 'manifest', label: t.ops_tab_manifest, icon: Briefcase, count: manifests.length },
          { id: 'customs', label: t.ops_tab_customs, icon: FileText, count: customsDocs.length },
          { id: 'local', label: lang === 'id' ? 'Local Trucking / Gudang' : 'Local Trucking / Storage', icon: Truck, count: localProjects.length },
        ].map(tb => {
          const Icon = tb.icon;
          const active = tab === tb.id;
          return (
            <button key={tb.id} onClick={() => setTab(tb.id)} style={{background: 'transparent', border: 'none', padding: '10px 16px', cursor: 'pointer', fontFamily: 'inherit', fontSize: '12px', fontWeight: 500, color: active ? 'var(--ims-accent)' : 'var(--ims-text-2)', borderBottom: active ? '2px solid var(--ims-border)' : '2px solid transparent', marginBottom: '-1px', display: 'flex', alignItems: 'center', gap: '7px', letterSpacing: '0.03em'}}>
              <Icon size={14} strokeWidth={1.5} />{tb.label}
              <span style={{padding: '2px 7px', background: active ? 'var(--ims-accent)' : 'var(--ims-border)', color: active ? 'var(--ims-text)' : 'var(--ims-text-2)', fontSize: '10px', fontWeight: 600, borderRadius: '10px'}}>{tb.count}</span>
            </button>
          );
        })}
      </div>

      {tab === 'shipment' && (
        <div style={{display: 'flex', flexDirection: 'column', gap: '14px'}}>
          {poProjects.map(p => {
            const effectiveShipping = getEffectiveShipping(p);
            const isSynced = p.manifestId && manifestById.has(p.manifestId);
            const linkedManifest = isSynced ? manifestById.get(p.manifestId) : null;
            return (
            <div key={p.id} style={{padding: '18px', background: 'var(--ims-bg-card)', border: '1px solid var(--ims-border)'}}>
              <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '14px', flexWrap: 'wrap', gap: '10px'}}>
                <div>
                  <div style={{fontSize: '14px', fontWeight: 600}}>{p.customer}</div>
                  <div style={{fontSize: '11px', color: 'var(--ims-text-2)', marginTop: '2px'}}>{p.subModality} · Qty {p.qty} · <span className="mono">{p.sphNo}</span></div>
                </div>
                <div className="mono" style={{fontSize: '14px', fontWeight: 500}}>{fmt(p.totalValue)}</div>
              </div>

              {/* Manifest link selector */}
              <div style={{display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '12px', flexWrap: 'wrap'}}>
                <span style={{fontSize: '10px', letterSpacing: '0.1em', textTransform: 'uppercase', color: 'var(--ims-text-2)', fontWeight: 600}}>{t.shipment_manifest_link}:</span>
                {canEdit ? (
                  <select value={p.manifestId || ''} onChange={e => linkManifest(p.id, e.target.value)} style={{padding: '4px 8px', fontSize: '11px', fontFamily: 'inherit', background: 'var(--ims-bg-card)', border: '1px solid var(--ims-border)', color: 'var(--ims-text)', cursor: 'pointer', maxWidth: '320px'}}>
                    <option value="">— {t.shipment_no_manifest} —</option>
                    {manifests.map(m => <option key={m.id} value={m.id}>{m.manifestNo} · {m.principal} ({t[`ops_status_${m.status}`]})</option>)}
                  </select>
                ) : (
                  <span style={{fontSize: '11px', color: linkedManifest ? 'var(--ims-accent)' : 'var(--ims-text-2)'}}>{linkedManifest ? `${linkedManifest.manifestNo} · ${linkedManifest.principal}` : t.shipment_no_manifest}</span>
                )}
                {isSynced && <span style={{padding: '2px 8px', fontSize: '9px', background: 'var(--ims-accent-2)20', color: 'var(--ims-accent-2)', fontWeight: 600, letterSpacing: '0.05em', textTransform: 'uppercase', borderRadius: '3px'}}>🔗 {t.shipment_auto_synced}</span>}
              </div>

              <div style={{display: 'flex', gap: '0', marginBottom: '14px'}}>
                {shippingSteps.map((step, i) => {
                  const isActive = effectiveShipping === step.id;
                  const stepIdx = shippingSteps.findIndex(s => s.id === effectiveShipping);
                  const isPast = stepIdx > i;
                  return (
                    <button key={step.id} onClick={() => !isSynced && updateShipping(p.id, step.id)} disabled={!canEdit || isSynced} title={isSynced ? t.shipment_auto_synced : ''} style={{flex: 1, padding: '9px 6px', fontSize: '9px', fontWeight: 600, letterSpacing: '0.05em', background: isActive ? step.color : isPast ? step.color + '40' : 'transparent', color: isActive ? '#fff' : isPast ? step.color : 'var(--ims-text-2)', border: `1px solid ${isActive || isPast ? step.color : 'var(--ims-border)'}`, cursor: (canEdit && !isSynced) ? 'pointer' : 'default', fontFamily: 'inherit', textTransform: 'uppercase', opacity: isSynced && !isActive && !isPast ? 0.6 : 1}}>{step.label}</button>
                  );
                })}
              </div>
              <div style={{display: 'flex', alignItems: 'center', gap: '10px', flexWrap: 'wrap'}}>
                <span style={{fontSize: '10px', letterSpacing: '0.15em', textTransform: 'uppercase', color: 'var(--ims-text-2)', fontWeight: 600}}>{t.customs_status}:</span>
                {['released', 'ongoing', 'hold'].map(status => (
                  <button key={status} onClick={() => updateCustoms(p.id, status)} disabled={!canEdit} style={{padding: '5px 11px', fontSize: '11px', fontFamily: 'inherit', background: p.customsStatus === status ? (status === 'released' ? 'var(--ims-accent-2)' : status === 'ongoing' ? 'var(--ims-gold)' : '#8b3a3a') : 'transparent', color: p.customsStatus === status ? '#fff' : 'var(--ims-text-2)', border: `1px solid ${p.customsStatus === status ? 'transparent' : 'var(--ims-border)'}`, cursor: canEdit ? 'pointer' : 'default', fontWeight: 500}}>{t[`customs_${status}`]}</button>
                ))}
              </div>

              {/* Status Note - especially important for "hold" */}
              {(p.customsStatus === 'hold' || p.customsStatusNote) && (
                <div style={{marginTop: '12px', padding: '10px 12px', background: p.customsStatus === 'hold' ? '#8b3a3a10' : 'var(--ims-text)', borderLeft: `3px solid ${p.customsStatus === 'hold' ? '#8b3a3a' : 'var(--ims-gold)'}`}}>
                  <div style={{fontSize: '9px', letterSpacing: '0.15em', textTransform: 'uppercase', color: p.customsStatus === 'hold' ? '#8b3a3a' : 'var(--ims-text-2)', fontWeight: 600, marginBottom: '6px'}}>
                    {t.status_note_label} {p.customsStatus === 'hold' && <span style={{color: '#c03030'}}>* {t.status_note_hold_required}</span>}
                  </div>
                  {canEdit ? (
                    <CustomsNoteEditor value={p.customsStatusNote} isHold={p.customsStatus === 'hold'} onSave={note => saveStatusNote(p.id, note)} t={t} lang={lang} />
                  ) : (
                    <div style={{fontSize: '12px', color: 'var(--ims-text)', fontStyle: p.customsStatusNote ? 'normal' : 'italic'}}>{p.customsStatusNote || t.status_note_empty}</div>
                  )}
                </div>
              )}
            </div>
            );
          })}
          {poProjects.length === 0 && <div style={{padding: '40px', textAlign: 'center', color: 'var(--ims-text-2)', background: 'var(--ims-bg-card)', border: '1px solid var(--ims-border)'}}>{t.no_data}</div>}
        </div>
      )}

      {tab === 'manifest' && <ManifestList manifests={manifests} setManifests={setManifests} data={data} t={t} lang={lang} canEdit={canEdit} fmt={fmt} />}
      {tab === 'customs' && <CustomsDocsList customsDocs={customsDocs} setCustomsDocs={setCustomsDocs} manifests={manifests} t={t} lang={lang} canEdit={canEdit} />}
      {tab === 'local' && (
        <div style={{display: 'flex', flexDirection: 'column', gap: '12px'}}>
          {localProjects.map(p => (
            <div key={p.id} style={{padding: '16px', background: 'var(--ims-bg-card)', border: '1px solid var(--ims-border)'}}>
              <div style={{display: 'flex', justifyContent: 'space-between', gap: '12px', flexWrap: 'wrap', marginBottom: '12px'}}>
                <div>
                  <div style={{fontWeight: 700, fontSize: '14px'}}>{p.customer}</div>
                  <div style={{fontSize: '11px', color: 'var(--ims-text-2)', marginTop: '2px'}}>{p.subModality} · <span className="mono">{p.sphNo}</span></div>
                </div>
                <span style={{padding: '4px 10px', fontSize: '10px', background: (p.localDeliveryStatus === 'storing' ? '#1a4d8a' : 'var(--ims-accent-2)') + '25', color: p.localDeliveryStatus === 'storing' ? '#1a4d8a' : 'var(--ims-accent-2)', fontWeight: 700}}>
                  {p.localDeliveryStatus === 'storing' ? 'STORING' : 'ON DELIVERY'}
                </span>
              </div>
              <div style={{display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '10px'}}>
                <Field label={lang === 'id' ? 'Status Lokal' : 'Local Status'}>
                  <select disabled={!canEdit} value={p.localDeliveryStatus || 'on_delivery'} onChange={e => updateLocalDelivery(p.id, { localDeliveryStatus: e.target.value, sphWorkflowStatus: 'local_delivery', workflowEvent: 'local_delivery' })}>
                    <option value="on_delivery">On delivery (local trucking)</option>
                    <option value="storing">Storing di gudang</option>
                    <option value="delivered_to_rs">Tiba di RS</option>
                  </select>
                </Field>
                <Field label="ETA RS"><input disabled={!canEdit} type="date" value={p.localEta || ''} onChange={e => updateLocalDelivery(p.id, { localEta: e.target.value })} /></Field>
                <Field label={lang === 'id' ? 'Vendor Trucking' : 'Trucking Vendor'}><input disabled={!canEdit} value={p.localVendor || ''} onChange={e => updateLocalDelivery(p.id, { localVendor: e.target.value })} /></Field>
                <Field label={lang === 'id' ? 'Link Lampiran' : 'Attachment Link'}><input disabled={!canEdit} value={p.localAttachmentUrl || ''} onChange={e => updateLocalDelivery(p.id, { localAttachmentUrl: e.target.value })} placeholder="https://drive.google.com/..." /></Field>
              </div>
              {p.localNotes && <div style={{fontSize: '11px', color: 'var(--ims-text-2)', marginTop: '8px'}}>{p.localNotes}</div>}
            </div>
          ))}
          {localProjects.length === 0 && <div className="empty-state">{lang === 'id' ? 'Belum ada barang released / local trucking' : 'No released / local trucking items yet'}</div>}
        </div>
      )}
    </div>
  );
}

// ============== Manifest List ==============
function ManifestList({ manifests, setManifests, data, t, lang, canEdit, fmt }) {
  const [modalOpen, setModalOpen] = useState(false);
  const [editingRecord, setEditingRecord] = useState(null);
  const [sortBy, setSortBy] = useState('date_desc');
  const stages = getRegStages(recordType);
  const statusColors = { planning: '#94a3b8', loading: '#7d9cc5', in_transit: 'var(--ims-gold)', arrived: '#5b87b8', cleared: 'var(--ims-accent-2)' };

  // Build linked-SPH lookup: manifestId → array of linked PO projects
  const linkedByManifest = useMemo(() => {
    const map = new Map();
    (data || []).forEach(s => {
      if (s.manifestId) {
        if (!map.has(s.manifestId)) map.set(s.manifestId, []);
        map.get(s.manifestId).push(s);
      }
    });
    return map;
  }, [data]);

  const handleSave = (rec) => {
    setManifests(prev => {
      const exists = prev.find(r => r.id === rec.id);
      return exists ? prev.map(r => r.id === rec.id ? rec : r) : [...prev, rec];
    });
    setModalOpen(false); setEditingRecord(null);
  };
  const [deleteId, setDeleteId] = useState(null);
  const handleDelete = (id) => {
    if (!canEdit) return;
    setDeleteId(id);
  };
  const confirmDelete = () => {
    setManifests(prev => prev.filter(r => r.id !== deleteId));
    setDeleteId(null);
  };

  const sortedManifests = useMemo(() => {
    const arr = [...manifests];
    if (sortBy === 'date_desc') return arr.sort((a, b) => (b.etd || '').localeCompare(a.etd || ''));
    if (sortBy === 'date_asc') return arr.sort((a, b) => (a.etd || '').localeCompare(b.etd || ''));
    if (sortBy === 'value_desc') return arr.sort((a, b) => (b.totalValue || 0) - (a.totalValue || 0));
    if (sortBy === 'status') return arr.sort((a, b) => (a.status || '').localeCompare(b.status || ''));
    return arr;
  }, [manifests, sortBy]);

  return (
    <div style={{background: 'var(--ims-bg-card)', border: '1px solid var(--ims-border)'}}>
      <div style={{padding: '14px 18px', borderBottom: '1px solid var(--ims-border)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '10px'}}>
        <div className="serif" style={{fontSize: '17px', fontWeight: 500}}>{t.ops_tab_manifest}</div>
        <div style={{display: 'flex', alignItems: 'center', gap: '12px'}}>
          <SortToggle value={sortBy} onChange={setSortBy} lang={lang} options={[{value: 'date_desc', label: lang === 'id' ? 'Terbaru' : 'Newest'}, {value: 'date_asc', label: lang === 'id' ? 'Terlama' : 'Oldest'}, {value: 'value_desc', label: lang === 'id' ? 'Nilai Tertinggi' : 'Highest Value'}, {value: 'status', label: lang === 'id' ? 'Status' : 'Status'}]} />
          {canEdit && <button className="btn-primary" onClick={() => { setEditingRecord(null); setModalOpen(true); }} style={{fontSize: '11px', padding: '6px 12px'}}><Plus size={12} />{t.crud_add}</button>}
        </div>
      </div>
      {sortedManifests.map(m => {
        const statusColor = statusColors[m.status];
        const principalColor = m.principal === 'SG Healthcare' ? '#1a4d8a' : m.principal === 'ANKE' ? '#c03030' : m.principal === 'Hyde Medical' ? '#7b3fb5' : m.principal === 'SINO MDT' ? '#d4780a' : m.principal === 'Angell' ? '#0f7a5a' : '#b8860b';
        return (
          <div key={m.id} style={{padding: '16px 18px', borderTop: '1px solid var(--ims-border)'}}>
            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: '12px', flexWrap: 'wrap', marginBottom: '10px'}}>
              <div style={{flex: '1 1 320px'}}>
                <div style={{display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '4px', flexWrap: 'wrap'}}>
                  <span className="mono" style={{fontSize: '13px', fontWeight: 700, color: 'var(--ims-text)'}}>{m.manifestNo}</span>
                  <span style={{padding: '2px 8px', background: principalColor + '20', color: principalColor, fontSize: '10px', fontWeight: 700}}>{m.principal}</span>
                  <span style={{fontSize: '10px', color: 'var(--ims-text-2)'}}>· {m.principalOrigin}</span>
                </div>
                <div style={{fontSize: '11px', color: 'var(--ims-text)', marginTop: '4px'}}>🚢 {m.vessel} · <span className="mono">{m.containerNo}</span></div>
                <div style={{fontSize: '10px', color: 'var(--ims-text-2)', marginTop: '2px'}}>{m.portOfLoading} → {m.portOfDischarge}</div>
              </div>
              <div style={{textAlign: 'right', display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: '6px'}}>
                <span style={{padding: '4px 10px', fontSize: '10px', background: statusColor + '25', color: statusColor, fontWeight: 600, letterSpacing: '0.05em', textTransform: 'uppercase'}}>{t[`ops_status_${m.status}`]}</span>
                <div className="mono" style={{fontSize: '12px', fontWeight: 600}}>{fmt(m.totalValue)}</div>
                {canEdit && (
                  <div style={{display: 'flex', gap: '4px'}}>
                    <button onClick={() => { setEditingRecord(m); setModalOpen(true); }} style={{background: 'transparent', border: '1px solid var(--ims-border)', padding: '4px 8px', fontSize: '10px', cursor: 'pointer', color: 'var(--ims-text)', fontFamily: 'inherit'}}><Edit2 size={11} /></button>
                    <button onClick={() => handleDelete(m.id)} style={{background: 'transparent', border: '1px solid var(--ims-border)', padding: '4px 8px', fontSize: '10px', cursor: 'pointer', color: '#c03030', fontFamily: 'inherit'}}><Trash2 size={11} /></button>
                  </div>
                )}
              </div>
            </div>
            <div style={{display: 'flex', gap: '14px', flexWrap: 'wrap', fontSize: '10px', color: 'var(--ims-text-2)', marginBottom: '8px'}}>
              <span><strong>ETD:</strong> <span className="mono">{m.etd}</span></span>
              <span><strong>ETA:</strong> <span className="mono">{m.eta}</span></span>
              <span><strong>Items:</strong> {m.itemsCount}</span>
              <span><strong>Freight:</strong> <span className="mono">{fmt(m.freightCost)}</span></span>
              <span><strong>Insurance:</strong> <span className="mono">{fmt(m.insurance)}</span></span>
              {m.piRef && <span><strong>PI:</strong> <span className="mono">{m.piRef}</span></span>}
            </div>
            {m.notes && <div style={{padding: '8px 10px', background: 'var(--ims-bg-card-2)', fontSize: '11px', fontStyle: 'italic', color: 'var(--ims-text)'}}>📝 {m.notes}</div>}
            {linkedByManifest.has(m.id) && (
              <div style={{marginTop: '8px', padding: '8px 10px', background: 'var(--ims-accent-2)10', borderLeft: '3px solid var(--ims-accent-2)'}}>
                <div style={{fontSize: '9px', letterSpacing: '0.1em', textTransform: 'uppercase', color: 'var(--ims-accent-2)', fontWeight: 600, marginBottom: '4px'}}>🔗 {lang === 'id' ? 'PO Terhubung' : 'Linked PO'} ({linkedByManifest.get(m.id).length})</div>
                {linkedByManifest.get(m.id).map(s => (
                  <div key={s.id} style={{fontSize: '11px', color: 'var(--ims-text)', marginTop: '2px'}}>• {s.customer} — {s.subModality} <span className="mono" style={{fontSize: '10px', color: 'var(--ims-text-2)'}}>({s.sphNo})</span></div>
                ))}
              </div>
            )}
          </div>
        );
      })}
      {manifests.length === 0 && <div className="empty-state">{t.no_data}</div>}
      {modalOpen && <ManifestModal record={editingRecord} onSave={handleSave} onClose={() => { setModalOpen(false); setEditingRecord(null); }} t={t} lang={lang} />}
      <ConfirmDialog open={!!deleteId} title={lang === 'id' ? 'Hapus Manifest?' : 'Delete Manifest?'} message={lang === 'id' ? 'Yakin ingin menghapus data ini? Tindakan ini tidak dapat dibatalkan.' : 'Are you sure you want to delete this record? This action cannot be undone.'} onConfirm={confirmDelete} onCancel={() => setDeleteId(null)} danger lang={lang} />
    </div>
  );
}

// ============== Customs Docs List ==============
function CustomsDocsList({ customsDocs, setCustomsDocs, manifests, t, lang, canEdit }) {
  const [modalOpen, setModalOpen] = useState(false);
  const [editingRecord, setEditingRecord] = useState(null);
  const [sortBy, setSortBy] = useState('date_desc');
  const statusColors = { received: '#94a3b8', submitted: 'var(--ims-gold)', approved: 'var(--ims-accent-2)', rejected: '#c03030' };

  const handleSave = (rec) => {
    setCustomsDocs(prev => {
      const exists = prev.find(r => r.id === rec.id);
      return exists ? prev.map(r => r.id === rec.id ? rec : r) : [...prev, rec];
    });
    setModalOpen(false); setEditingRecord(null);
  };
  const [deleteId, setDeleteId] = useState(null);
  const handleDelete = (id) => {
    if (!canEdit) return;
    setDeleteId(id);
  };
  const confirmDelete = () => {
    setCustomsDocs(prev => prev.filter(r => r.id !== deleteId));
    setDeleteId(null);
  };

  const sortedDocs = useMemo(() => {
    const arr = [...customsDocs];
    if (sortBy === 'date_desc') return arr.sort((a, b) => (b.docDate || '').localeCompare(a.docDate || ''));
    if (sortBy === 'date_asc') return arr.sort((a, b) => (a.docDate || '').localeCompare(b.docDate || ''));
    if (sortBy === 'value_desc') return arr.sort((a, b) => (b.totalValue || 0) - (a.totalValue || 0));
    if (sortBy === 'status') return arr.sort((a, b) => (a.status || '').localeCompare(b.status || ''));
    return arr;
  }, [customsDocs, sortBy]);

  return (
    <div style={{background: 'var(--ims-bg-card)', border: '1px solid var(--ims-border)', overflowX: 'auto'}}>
      <div style={{padding: '14px 18px', borderBottom: '1px solid var(--ims-border)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '10px'}}>
        <div className="serif" style={{fontSize: '17px', fontWeight: 500}}>{t.ops_tab_customs}</div>
        <div style={{display: 'flex', alignItems: 'center', gap: '12px'}}>
          <SortToggle value={sortBy} onChange={setSortBy} lang={lang} options={[{value: 'date_desc', label: lang === 'id' ? 'Terbaru' : 'Newest'}, {value: 'date_asc', label: lang === 'id' ? 'Terlama' : 'Oldest'}, {value: 'status', label: lang === 'id' ? 'Status' : 'Status'}]} />
          {canEdit && <button className="btn-primary" onClick={() => { setEditingRecord(null); setModalOpen(true); }} style={{fontSize: '11px', padding: '6px 12px'}}><Plus size={12} />{t.crud_add}</button>}
        </div>
      </div>
      <table style={{width: '100%', borderCollapse: 'collapse', fontSize: '12px', minWidth: '800px'}}>
        <thead>
          <tr style={{background: 'var(--ims-bg-card-2)'}}>
            <Th>{t.ops_doc_no}</Th><Th>{t.ops_doc_type}</Th>
            <Th>{t.imp_principal}</Th><Th>Manifest</Th>
            <Th>{t.ops_doc_date}</Th><Th>{t.ops_doc_status}</Th>
            {canEdit && <Th align="right">{t.crud_actions}</Th>}
          </tr>
        </thead>
        <tbody>
          {sortedDocs.map(d => {
            const statusColor = statusColors[d.status];
            return (
              <tr key={d.id} className="hover-row" style={{borderTop: '1px solid var(--ims-border)'}}>
                <Td>
                  <span className="mono" style={{fontSize: '11px', fontWeight: 600}}>{d.docNo}</span>
                  {d.fileUrl && <div style={{marginTop: '4px'}}><LinkAttachment url={d.fileUrl} lang={lang} /></div>}
                  {d.notes && <div style={{fontSize: '10px', color: 'var(--ims-text-2)', marginTop: '2px', fontStyle: 'italic'}}>{d.notes}</div>}
                </Td>
                <Td><span style={{padding: '2px 7px', fontSize: '10px', background: 'var(--ims-border)', color: 'var(--ims-text)', fontWeight: 600}}>{t[`ops_doc_${d.docType}`]}</span></Td>
                <Td><span style={{fontSize: '11px'}}>{d.principal}</span></Td>
                <Td><span className="mono" style={{fontSize: '10px'}}>{d.manifestRef || '—'}</span></Td>
                <Td><span className="mono" style={{fontSize: '11px'}}>{d.docDate}</span></Td>
                <Td><span style={{padding: '3px 8px', fontSize: '10px', background: statusColor + '25', color: statusColor, fontWeight: 600, letterSpacing: '0.05em', textTransform: 'uppercase'}}>{t[`ops_doc_${d.status}`]}</span></Td>
                {canEdit && (
                  <Td align="right">
                    <button onClick={() => { setEditingRecord(d); setModalOpen(true); }} style={{background: 'transparent', border: '1px solid var(--ims-border)', padding: '4px 8px', fontSize: '10px', cursor: 'pointer', color: 'var(--ims-text)', fontFamily: 'inherit', marginRight: '4px'}}><Edit2 size={11} /></button>
                    <button onClick={() => handleDelete(d.id)} style={{background: 'transparent', border: '1px solid var(--ims-border)', padding: '4px 8px', fontSize: '10px', cursor: 'pointer', color: '#c03030', fontFamily: 'inherit'}}><Trash2 size={11} /></button>
                  </Td>
                )}
              </tr>
            );
          })}
        </tbody>
      </table>
      {customsDocs.length === 0 && <div className="empty-state">{t.no_data}</div>}
      {modalOpen && <CustomsDocModal record={editingRecord} manifests={manifests} onSave={handleSave} onClose={() => { setModalOpen(false); setEditingRecord(null); }} t={t} lang={lang} />}
      <ConfirmDialog open={!!deleteId} title={lang === 'id' ? 'Hapus Dokumen?' : 'Delete Document?'} message={lang === 'id' ? 'Yakin ingin menghapus data ini? Tindakan ini tidak dapat dibatalkan.' : 'Are you sure you want to delete this record? This action cannot be undone.'} onConfirm={confirmDelete} onCancel={() => setDeleteId(null)} danger lang={lang} />
    </div>
  );
}

